from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict


def apply_dynamic_filters(
    search_results: List[SearchResult],
    filter_specs: Dict[str, Dict[str, Any]],
    filter_logic: str = "AND"
) -> List[SearchResult]:
    """Apply dynamic metadata filters to search results with configurable logic.

    Args:
        search_results: List of SearchResult objects to filter
        filter_specs: Dictionary of filter specifications.
            Format: {"field_name": {"operator": value}}
            Example: {"category": {"==": "tech"}, "rating": {">=": 4.0}}
        filter_logic: "AND" (all filters must match) or "OR" (any filter matches)

    Returns:
        Filtered list of SearchResult objects
    """
    # Handle empty filter specs or results
    if not filter_specs or not search_results:
        return search_results

    # Create metadata filter engine
    filter_engine = MetadataFilterEngine()

    filtered_results = []

    for result in search_results:
        # Convert SearchResult to dictionary format for filtering
        if hasattr(result, 'metadata'):
            result_dict = result.metadata
        elif hasattr(result, 'to_dict'):
            result_dict = result.to_dict()
        else:
            result_dict = result.__dict__

        # Evaluate all filter conditions for this result
        match_results = []

        for field_name, operator_value in filter_specs.items():
            for operator, value in operator_value.items():
                # Check if this field-operator-value condition matches
                matches = filter_engine.evaluate(
                    result_dict, 
                    field_name, 
                    operator, 
                    value
                )
                match_results.append(matches)

        # Apply logic combination (AND or OR)
        if filter_logic.upper() == "AND":
            # All filters must match
            if match_results and all(match_results):
                filtered_results.append(result)
        elif filter_logic.upper() == "OR":
            # At least one filter must match
            if match_results and any(match_results):
                filtered_results.append(result)
        else:
            # Default to AND logic for unknown filter_logic values
            if match_results and all(match_results):
                filtered_results.append(result)

    return filtered_results

